import{_ as t,o as s,c as r,a6 as i,g3 as p,g4 as o,g5 as l,g6 as n,g7 as e,g8 as g,g9 as h,ga as d,eF as m,eG as c,gb as _,gc as u,gd as b}from"./chunks/framework.UYVGz2W_.js";const I=JSON.parse('{"title":"見積もりおよびチームのノルマ","description":"","frontmatter":{},"headers":[],"relativePath":"ja/estimation/index.md","filePath":"ja/estimation/index.md"}'),f={name:"ja/estimation/index.md"};function x(P,a,k,S,T,K){return s(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="見積もりおよびチームのノルマ" tabindex="-1">見積もりおよびチームのノルマ <a class="header-anchor" href="#見積もりおよびチームのノルマ" aria-label="Permalink to “見積もりおよびチームのノルマ”">​</a></h1><p>各タスクの見積もり作業は大変な作業のように感じられるかもしれませんが、そのメリットは努力をはるかに上回ります。タスクの見積もりを記入することで、以下のことが可能になります。</p><ul><li>制作中のタスクの見積もり日数を明確に把握できます。</li><li>タスクの見積もり時間を実際の所要時間と簡単に比較でき、今後のタスクをより正確に予測できます。</li><li>タスクの見積もり、開始日、期限が確定したら、エンティティスケジュールまたはチームスケジュールからタスクを調整できます。</li><li>アーティストが各タスクに費やすべき時間を意識し、整理された状態を維持できるよう支援します。</li><li>現在および将来の制作に関する予測を改善します。</li></ul><p>Kitsuは、タスクの見積もりを簡単に追跡、確認、予測できるさまざまな機能を提供しています。 それらを可能にする機能の一部を見てみましょう。</p><h2 id="タスクの見積もりを追加する" tabindex="-1">タスクの見積もりを追加する <a class="header-anchor" href="#タスクの見積もりを追加する" aria-label="Permalink to “タスクの見積もりを追加する”">​</a></h2><p>まず、タスクタイプの名前をクリックします。</p><p><img src="'+p+'" alt="タスクタイプ"></p><p>すると、[詳細タスクタイプ] ビューが表示されます。ここでは、特定のタスクタイプのすべてのタスクのリストと、追加の詳細を確認できます。</p><p><img src="'+o+'" alt="スーパーバイザーページ"></p><p>タスクに見積もりを追加するには、[見積もり (Est.)] フィールドをクリックし、日数を入力します。 <strong>Ctrl/Cmd</strong> または <strong>Shift</strong> キーを押しながら複数のタスクを選択し、選択したすべてのタスクに同じ見積もりを適用することができます。</p><p>::: ヒント 期間は、タスクに実際に要した時間を表し、記録された時間から自動的に計算されます。この点については、後ほど詳しく説明します。 :::</p><p>フィールドをクリックしてポップアップカレンダーから日付を選択することで、<strong>開始日</strong>を定義することもできます。</p><p><strong>期限</strong>は、入力された<strong>見積もり</strong>と<strong>開始日</strong>に基づいて自動的に計算されます。</p><p><img src="'+l+'" alt="開始日"></p><h3 id="詳細なタスクタイプビューの機能" tabindex="-1">詳細なタスクタイプビューの機能: <a class="header-anchor" href="#詳細なタスクタイプビューの機能" aria-label="Permalink to “詳細なタスクタイプビューの機能:”">​</a></h3><p>詳細なタスクタイプビューで利用できるケースと機能の概要は以下の通りです。</p><ul><li>タスクのステータスを確認および変更する</li><li>タスクに担当者を割り当てる</li><li>タスクの見積もり（日数）を追加する</li><li>アーティストのタイムシートから記録された時間の累計を確認する</li><li>やりとりの回数をリテイクのステータスで追跡する</li><li>カレンダー選択機能を使用してタスクの開始日を追加する</li><li>開始日と見積もりに基づいて自動生成された期限を確認する</li><li>WIP（作業中）とフィードバックの日付が自動的に入力されていることを確認する</li><li>最新のコメントセクションを監視して、このタスクタイプの最新アクティビティを常に把握する</li></ul><h2 id="チームの速度予測" tabindex="-1">チームの速度予測 <a class="header-anchor" href="#チームの速度予測" aria-label="Permalink to “チームの速度予測”">​</a></h2><h3 id="予測クォータを使用したチームの速度予測" tabindex="-1">予測クォータを使用したチームの速度予測 <a class="header-anchor" href="#予測クォータを使用したチームの速度予測" aria-label="Permalink to “予測クォータを使用したチームの速度予測”">​</a></h3><p>正確な予測を設定するには、<strong>[予測]</strong> タブを使用します。</p><p><img src="'+n+'" alt="予測タブ"></p><p>左半分には、割り当てとフレーム数（1）とともにタスクがリスト表示されます。制作に設定した<strong>FPS</strong>に基づいて、<strong>秒</strong>数が自動的に計算されます（2）。</p><p>::: ヒント 定義 <strong>クォータ</strong>は、<strong>チームの速度</strong>を視覚化します。</p><p>アーティストが<strong>予定日数</strong>内にすべてのタスクを完了するために、1日に平均して何ショット、何フレーム、何秒必要かを把握できます。 :::</p><p>右半分には、部門チーム全体（割り当てられたタスクに基づく）、完了に必要なショット数、フレーム数、秒数、平均ノルマが表示されます。また、<strong>残り</strong>行も表示され、チームの現在の状況がわかります。</p><p>最後の列は<strong>見積もり</strong>です。見積もりを変更するには、行をマウスでポイントし、編集可能なエリアをクリックします。</p><p>また、複数のタスクを同時に選択して、一度にすべてを編集することもできます。</p><p><img src="'+e+'" alt="見積もりタブの編集"></p><p>右側の<strong>見積もり</strong>（日数）を変更するたびに、<strong>平均ノルマ</strong>がリアルタイムで更新されます。</p><p><strong>スケジュール</strong>タブの詳細については、<a href="./../schedules/#set-a-task-estimation">タスクタイプのスケジュール</a>を参照してください。</p><h2 id="ノルマ" tabindex="-1">ノルマ <a class="header-anchor" href="#ノルマ" aria-label="Permalink to “ノルマ”">​</a></h2><h3 id="チームのスピードを把握するためのノルマの使用" tabindex="-1">チームのスピードを把握するためのノルマの使用 <a class="header-anchor" href="#チームのスピードを把握するためのノルマの使用" aria-label="Permalink to “チームのスピードを把握するためのノルマの使用”">​</a></h3><p>Kitsuには、<strong>タスクの種類</strong>ごとにノルマを計算する方法が2つあります。</p><h3 id="タイムシートに基づくノルマ" tabindex="-1">タイムシートに基づくノルマ <a class="header-anchor" href="#タイムシートに基づくノルマ" aria-label="Permalink to “タイムシートに基づくノルマ”">​</a></h3><p>最初の方法はタイムシートとリンクしています。 最初のフィードバックリクエストが行われた時点でショットが完了したと見なされます。 アーティストがタイムシートに記録したタスクに費やした時間に応じて、ノルマに重みが付けられます。</p><p><img src="'+g+'" alt="Quotas stat page day weighted"></p><p>この例では、Kitsuはタイムシートの入力内容に基づいて日々のノルマを加重します。</p><p><img src="'+h+'" alt="Quotas stat page day weighted detail"></p><h3 id="ステータス変更に基づくノルマ" tabindex="-1">ステータス変更に基づくノルマ <a class="header-anchor" href="#ステータス変更に基づくノルマ" aria-label="Permalink to “ステータス変更に基づくノルマ”">​</a></h3><p>タイムシートが記入されていない場合、Kitsuはステータス変更を使用して期間を推定します。</p><ul><li>タスクは、WIPへの最初のステータス変更が発生した時点で開始されたと見なされます。</li><li>タスクは、フィードバックリクエストが作成された日に完了したと見なされます。</li></ul><p>その後、Kitsuは開始日と終了日の間の全営業日にわたって完了したフレームを分配します。 アーティストごとに、1日/1週間/1か月あたりの完了フレーム数（または秒数、またはタスク数）を計算します。</p><p><img src="'+d+'" alt="Quotas stat page day status"></p><p>いつでも数字をクリックすると、右パネルに詳細が表示されます。</p><h2 id="優先度の変更" tabindex="-1">優先度の変更 <a class="header-anchor" href="#優先度の変更" aria-label="Permalink to “優先度の変更”">​</a></h2><p>優先順位は制作中に頻繁に変更されることがあり、この優先順位の変更をチームに簡単に知らせたい場合があります。</p><p>これを行うには、タスクのステータス（1）の近くのスペースをクリックします。</p><p><img src="'+m+'" alt="タスクの割り当て"></p><p>アクションボックスが表示されます。</p><p><img src="'+c+'" alt="青いメニュー"></p><p>アクションメニューのアイコンをクリックして、<strong>優先度の変更</strong>を選択します。</p><p><img src="'+_+'" alt="優先度の変更"></p><p>優先度には、すべてのタスクのデフォルト値である<strong>「通常」</strong>、<strong>「高」</strong>、<strong>「非常に高い」</strong>、<strong>「緊急」</strong>の4つのレベルがあります。<strong>「確認」</strong>ボタンで変更を保存します。</p><p>ステータスや担当者と同様に、複数のタスクを選択して「選択したタスクの優先度を変更」を選択することで、複数のタスクの優先度を同時に変更することができます。</p><p><img src="'+u+'" alt="優先度の選択"></p><p>タスクのステータスの横に感嘆符が表示されます。感嘆符の数が多いほど、タスクの緊急度が高いことを示します。</p><ul><li>(1) は <strong>通常</strong></li><li>(2) は <strong>高</strong></li><li>(3) は <strong>非常に高い</strong></li><li>(4) は <strong>緊急</strong></li></ul><p><img src="'+b+'" alt="優先度レベル"></p>',58)])])}const $=t(f,[["render",x]]);export{I as __pageData,$ as default};
